  ('bookkeeper-moex-00762', 'bookkeeper', 'bookkeeper-moex-108-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '文山有限公司107年全年課稅所得額40萬元，依現行所得稅法規定，其應納107年度營利事業所得稅為 多少？', '["$68,000", "$72,000", "$76,000", "$80,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "649483717ea0", "answer_pdf_sha1": "e003a99a2c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
